let domainFilter = dynamic([{Domain}]);
DMARCReports_CL
| where TimeGenerated {TimeRange}
| where '*' in (domainFilter) or Domain in (domainFilter)
| summarize Messages = sum(MessageCount) by PolicyEvaluated_disposition
| sort by Messages desc

let domainFilter = dynamic([{Domain}]);
DMARCReports_CL
| where TimeGenerated {TimeRange}
| where '*' in (domainFilter) or Domain in (domainFilter)
| summarize Messages = sum(MessageCount) by SpfResult
| sort by Messages desc

let domainFilter = dynamic([{Domain}]);
DMARCReports_CL
| where TimeGenerated {TimeRange}
| where '*' in (domainFilter) or Domain in (domainFilter)
| summarize Messages = sum(MessageCount) by DkimResult
| sort by Messages desc

let domainFilter = dynamic([{Domain}]);
DMARCReports_CL
| where TimeGenerated {TimeRange}
| where '*' in (domainFilter) or Domain in (domainFilter)
| summarize Reports = dcount(ReportId) by bin(TimeGenerated, 1d), ReportOrgName
| sort by TimeGenerated asc

let domainFilter = dynamic([{Domain}]);
DMARCReports_CL
| where TimeGenerated {TimeRange}
| where '*' in (domainFilter) or Domain in (domainFilter)
| summarize arg_max(TimeGenerated, PolicyPublished_p, PolicyPublished_sp, PolicyPublished_pct, PolicyPublished_adkim, PolicyPublished_aspf) by Domain
| project Domain, Policy=PolicyPublished_p, SubdomainPolicy=PolicyPublished_sp, Pct=PolicyPublished_pct, DKIM_Alignment=PolicyPublished_adkim, SPF_Alignment=PolicyPublished_aspf
